import React, { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [expenses, setExpenses] = useState([]);
  const [title, setTitle] = useState("");
  const [amount, setAmount] = useState("");
  const [error, setError] = useState(null);

  // 👉 GET
  useEffect(() => {
    fetchExpenses();
  }, []);

  const fetchExpenses = async () => {
    setError(null);

    try {
      const res = await axios.get("http://localhost:8000/api/expenses/");
      setExpenses(res.data);
    } catch (err) {
      console.error(err);
      setError(
        "Unable to load expenses. Make sure the backend server is running on http://localhost:8000."
      );
    }
  };

  // 👉 POST
  const addExpense = async (e) => {
    e.preventDefault();
    setError(null);

    try {
      await axios.post("http://localhost:8000/api/expenses/", {
        title,
        amount,
      });

      setTitle("");
      setAmount("");
      fetchExpenses();
    } catch (err) {
      console.error(err);
      setError("Unable to add expense. Please make sure the backend is running.");
    }
  };

  const deleteExpense = async (id) => {
    setError(null);

    try {
      await axios.delete(`http://localhost:8000/api/expenses/${id}/`);
      fetchExpenses();
    } catch (err) {
      console.error(err);
      setError("Unable to delete expense. Please make sure the backend is running.");
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Expense Tracker</h2>
      {error && (
        <div style={{ color: "#b00", marginBottom: "16px" }}>
          {error}
        </div>
      )}

      <form onSubmit={addExpense}>
        <input
          placeholder="Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />

        <input
          placeholder="Amount"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
        />

        <button type="submit">Add</button>
      </form>

      <hr />

  {expenses.map((exp) => (
    <div key={exp.id}>
       {exp.title} - ₹{exp.amount}

        <button onClick={() => deleteExpense(exp.id)}>
          Delete
        </button>

        </div>
      ))}
    </div>
  );
}

export default App;
